        "+",
        "+    /**",
        "+     * @brief 获取渲染对象数量",
        "+     */",
        "+    size_t getObjectCount() const { return renderObjects_.size(); }",
        "+",
        "+    // ================================================================",
        "+    // 物理状态同步",
        "+    // ================================================================",
        "+",
        "+    /**",
        "+     * @brief 更新单个对象的变换",
        "+     * @param objectId 物理对象 ID",
        "+     * @param position 新位置",
        "+     * @param rotation 新旋转",
        "+     *",
        "+     * 标记对象需要在下一帧应用变换更新。",
        "+     * Filament 的 TransformManager 会在应用时更新世界矩阵。",
        "+     */",
        "+    void updateTransform(uint32_t objectId,",
        "+                         const Vec3& position,",
        "+                         const Quat& rotation);",
        "+",
        "+    /**",
        "+     * @brief 从世界快照批量同步状态",
        "+     * @param snapshot 物理世界快照",
        "+     *",
        "+     * 遍历快照中的所有对象，更新对应的渲染变换。",
