        "+        if (data.renderEntity != utils::Entity::INVALID() && transformMgr_) {",
        "+            transformMgr_->destroy(data.renderEntity);",
        "+        }",
        "+    }",
        "+",
        "+    renderObjects_.clear();",
        "+    materialCache_.clear();",
        "+",
        "+    std::cout << "[RenderingObjectManager] Destroyed. " << renderObjects_.size()",
