        "+bool RenderingObjectManager::createObject(uint32_t objectId,",
        "+                                           const RenderObjectConfig& config) {",
        "+    if (!engine_ || !scene_) {",
        "+        std::cerr << "[RenderingObjectManager] Engine or scene is null!" << std::endl;",
