        "+    // 构建渲染对象",
        "+    RenderObjectData& data = renderObjects_[objectId];",
        "+    data.renderEntity = entity;",
        "+    data.position = Vec3{0.0f, 0.0f, 0.0f};",
        "+    data.rotation = Quat::Identity();",
