        "+ *",
        "+ * 功能：",
        "+ * 1. 连接到 PhysicsSync 服务器",
        "+ * 2. 接收物理状态快照并映射到渲染对象",
        "+ * 3. WASD 键盘控制玩家物体",
        "+ * 4. 可选的 Filament 渲染输出",
        "+ */",
        "+",
        "+#include "physics_client.h"",
        "+#include "../common/physics_state.h"",
        "+#include "../common/timestep_manager.h"",
        "+#include <iostream>",
        "+#include <thread>",
        "+#include <chrono>",
        "+#include <csignal>",
        "+#include <cstring>",
        "+#include <cstdlib>",
        "+#include <atomic>",
        "+",
        "+namespace PhysicsSync {",
        "+",
        "+// ================================================================",
        "+// 全局变量",
        "+// ================================================================",
        "+",
        "+PhysicsClient* g_client = nullptr;",
        "+std::atomic<bool> g_running{true};",
        "+",
        "+/**",
        "+ * @brief 信号处理器 - 优雅退出",
        "+ */",
        "+void SignalHandler(int signal) {",
        "+    (void)signal;",
        "+    g_running = false;",
        "+    if (g_client && g_client->IsConnected()) {",
        "+        std::cout << "\n[Main] Received signal " << signal",
        "+                  << ", shutting down..." << std::endl;",
        "+        g_client->Stop();",
        "+    }",
        "+}",
        "+",
        "+} // namespace PhysicsSync",
        "+",
        "+#ifdef RENDERING_ENABLED",
        "+// === ================================================================",
        "+// 渲染路径（Filament 可用时）",
        "+// === ================================================================",
        "+",
        "+#include "FilamentRenderer.h"",
        "+#include "RenderingObjectManager.h"",
        "+#include "InputHandler.h"",
        "+",
        "+#include <windows.h>",
        "+",
        "+// 前向声明 Windows 消息处理函数",
        "+LRESULT WINAPI WndProc(HWND hwnd, UINT msg, WPARAM wParam, LPARAM lParam);",
