        "+// 全局渲染对象",
        "+static PhysicsSync::FilamentRenderer g_renderer;",
        "+static PhysicsSync::RenderingObjectManager g_renderMgr{nullptr, nullptr};",
        "+static PhysicsSync::InputHandler g_inputHandler;",
